INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (1, 'Portugal adopted a parliamentary republic under the 1976 Constitution following the Carnation Revolution that ended 48 years of authoritarian rule. The President holds a largely ceremonial role, while executive power rests with the Prime Minister and Council of Ministers, who are accountable to the elected Assembly of the Republic.', 'governance', 'en', 'Governance Principles');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (2, 'Universal suffrage has been guaranteed in Portugal since the 1976 Constitution, extended to all citizens over 18 regardless of gender, ethnicity, or social status. The right to vote was one of the core democratic achievements of the post-revolutionary settlement.', 'distribution_of_power', 'en', 'Distribution of Power');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (3, 'Portugal''s Constitution guarantees equal rights to all citizens regardless of national or ethnic origin. As a country shaped by emigration and with significant immigrant communities from Portuguese-speaking Africa and Brazil, Portugal has adopted legal frameworks promoting integration and equal treatment.', 'citizenship', 'en', 'Citizenship');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (4, 'While Portugal maintains a Concordat with the Holy See on specific matters such as Church property and religious marriage recognition, the 1976 Constitution formally separates Church from State. Religious institutions have no formal political role and the state is constitutionally non-denominational.', 'church_state', 'en', 'Church & State');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (5, 'Portugal''s public administration is largely staffed through competitive recruitment, but senior and political positions are appointed by the government of the day. Reform efforts since EU accession have professionalised the civil service, though political appointment at senior levels remains standard practice.', 'bureaucracy', 'en', 'Bureaucracy');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (6, 'Portugal abolished mandatory military service in 2004 and now maintains a fully professional volunteer force. The Armed Forces are integrated into NATO and EU defence structures, with a relatively small force focused on international deployments and collective defence commitments.', 'army', 'en', 'Army Model');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (7, 'As an Atlantic nation with one of the largest exclusive economic zones in Europe, Portugal maintains a navy focused on protecting maritime trade routes and patrolling its vast ocean territory. The navy plays no power projection role but is critical for fisheries enforcement and Atlantic security cooperation.', 'navy', 'en', 'Navy Model');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (8, 'Portugal''s Constitution guarantees extensive civil liberties including freedom of assembly, expression, and habeas corpus. Security services operate under judicial and parliamentary oversight, and the country consistently ranks among the most peaceful and free nations in global indices.', 'internal_security', 'en', 'Internal Security');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (9, 'Portugal operates a mixed economy where the state plays a significant role through public enterprises, regulation, and social spending. Following the 2008 financial crisis and IMF bailout, market-oriented reforms were introduced, but the state retains ownership of key infrastructure and the Constitution includes provisions for a mixed economy model.', 'economic_system', 'en', 'Economic System');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (10, 'As an EU member state, Portugal operates within the EU single market and common external tariff, making free trade with EU partners constitutionally enshrined. Portugal is deeply integrated into global trade through its Atlantic port infrastructure, serving as a gateway between Europe, the Americas, and Africa.', 'trade', 'en', 'Trade Policy');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (11, 'Portugal operates a progressive income tax (IRS) with rates ranging from 13.25% to 53%, alongside a corporate tax with progressive elements. The system is broadly redistributive, though significant dependence on VAT means consumption taxes also contribute heavily to state revenue.', 'taxation', 'en', 'Taxation');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (12, 'Following the 1974 revolution''s radical land collectivisations in the Alentejo, most agricultural land was returned to private ownership during the 1980s. Today Portugal''s agricultural sector is predominantly commercial, with large agribusinesses in the south and smaller family farms in the north.', 'land_reform', 'en', 'Land Reform');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (13, 'Portugal completed decolonisation following the 1974 Carnation Revolution, relinquishing its African territories and recognising East Timor''s independence in 2002. Portugal has no colonial policy and is a strong supporter of UN anti-colonialism frameworks.', 'colonization', 'en', 'Colonization');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (14, 'Portugal maintains two national police forces: the PSP for urban areas and the GNR for rural and border areas. Both operate under civilian oversight and democratic legal standards, with no evidence of systematic militarisation or political policing.', 'policing', 'en', 'Policing');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (15, 'Universal public education is guaranteed by the Portuguese Constitution, with compulsory schooling from ages 6 to 18. The state funds and operates the majority of schools, though private and cooperative institutions receive state subsidies and account for a significant minority of enrolment.', 'education', 'en', 'Education System');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (16, 'Portugal''s National Health Service (SNS), established in 1979, provides universal healthcare free at point of use for all citizens. Despite chronic underfunding and long waiting lists, the SNS remains the primary healthcare provider, supplemented by a growing private sector.', 'healthcare', 'en', 'Health System');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (17, 'Freedom of speech and of the press are guaranteed by the 1976 Constitution. Portugal consistently ranks in the top tier globally for press freedom. Hate speech laws exist but are narrowly applied, and political speech enjoys robust constitutional protection.', 'free_speech', 'en', 'Free Speech');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (18, 'Portugal''s Labour Code provides strong protections including a national minimum wage, paid annual leave, and significant dismissal protections. These rights were enshrined following the revolution and remain constitutionally guaranteed despite pressure during austerity periods.', 'labor_rights', 'en', 'Labor Rights');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (19, 'The right to form and join trade unions is constitutionally guaranteed in Portugal. Workers are free to organise, strike, and engage in collective bargaining. Major confederations CGTP and UGT represent workers across public and private sectors.', 'labor_associations', 'en', 'Labor Associations');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (20, 'Portuguese women gained full political and legal equality under the 1976 Constitution. Equal pay legislation, parental leave rights, and gender quotas for elected bodies are in force. Portugal ranks among the more gender-equal EU nations, though gaps persist in practice particularly in private sector leadership.', 'womens_rights', 'en', 'Rights of Women');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (21, 'Portugal operates a contributory social security system covering old age pensions, unemployment benefits, and disability support. The system underwent significant cuts during the 2011–2014 IMF adjustment programme but has since been partially restored and expanded.', 'welfare', 'en', 'Welfare');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (22, 'Portugal operates controlled immigration within the EU Schengen framework. As a destination for migrants from Portuguese-speaking countries in Africa and Brazil, Portugal has established specific legal pathways and integration programmes, though enforcement has tightened in recent years.', 'migration', 'en', 'Migration');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (23, 'Education is compulsory in Portugal from ages 6 to 18 and child labour is prohibited. Child welfare services are operated by the state and accredited NGOs. Portugal meets EU child welfare standards across all major indicators.', 'children_rights', 'en', 'Children''s Rights');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (24, 'Slavery was abolished in Portugal in 1761 on the mainland and 1869 in the colonies. All forms of forced labour and human trafficking are criminalised under the Penal Code. Portugal is a signatory to all major international anti-slavery and anti-trafficking conventions.', 'slavery', 'en', 'Slavery');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (25, 'Portugal has committed to carbon neutrality by 2045 and has expanded renewables significantly — over 60% of electricity was generated from renewables in recent years. However, full decarbonisation commitments across transport and industry remain moderate relative to the most ambitious EU member states.', 'environment', 'en', 'Environment');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (26, 'Portugal''s housing market combines a private rental and ownership market with a limited public housing stock. Following tourism-driven gentrification and a housing affordability crisis, the government introduced rent controls and public housing programmes, though critics argue supply-side interventions remain insufficient.', 'housing', 'en', 'Housing');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (27, 'Portugal adotou uma república parlamentar pela Constituição de 1976, após a Revolução dos Cravos que pôs fim a 48 anos de regime autoritário. O Presidente da República tem um papel maioritariamente representativo, cabendo o poder executivo ao Primeiro-Ministro e ao Conselho de Ministros, responsáveis perante a Assembleia da República.', 'governance', 'pt', 'Princípios de Governação');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (28, 'O sufrágio universal está garantido em Portugal desde a Constituição de 1976, extensível a todos os cidadãos maiores de 18 anos, independentemente do género, etnia ou estatuto social. O direito de voto foi uma das conquistas democráticas centrais do período pós-revolucionário.', 'distribution_of_power', 'pt', 'Distribuição do Poder');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (29, 'A Constituição portuguesa garante direitos iguais a todos os cidadãos independentemente da origem nacional ou étnica. Enquanto país marcado pela emigração e com significativas comunidades imigrantes de países lusófonos de África e do Brasil, Portugal adotou enquadramentos legais que promovem a integração e o tratamento igualitário.', 'citizenship', 'pt', 'Cidadania');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (30, 'Embora Portugal mantenha uma Concordata com a Santa Sé em matérias específicas como o património da Igreja e o reconhecimento do casamento religioso, a Constituição de 1976 consagra formalmente a separação entre a Igreja e o Estado. As instituições religiosas não têm papel político formal e o Estado é constitucionalmente laico.', 'church_state', 'pt', 'Igreja e Estado');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (31, 'A administração pública portuguesa é em grande medida recrutada por via concorrencial, embora os cargos de topo e de natureza política sejam nomeados pelo governo em funções. As reformas de modernização desde a adesão à UE profissionalizaram a função pública, ainda que a nomeação política nos escalões superiores permaneça uma prática corrente.', 'bureaucracy', 'pt', 'Burocracia');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (32, 'Portugal aboliu o serviço militar obrigatório em 2004 e mantém atualmente um exército profissional e voluntário. As Forças Armadas estão integradas na NATO e nas estruturas de defesa da UE, com um efetivo relativamente reduzido centrado em missões internacionais e na defesa coletiva.', 'army', 'pt', 'Modelo do Exército');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (33, 'Enquanto nação atlântica com uma das maiores zonas económicas exclusivas da Europa, Portugal mantém uma marinha vocacionada para a proteção das rotas comerciais marítimas e para a patrulha do seu vasto território oceânico. A marinha não tem ambições de projeção de poder, mas desempenha um papel essencial na fiscalização das pescas e na cooperação de segurança no Atlântico.', 'navy', 'pt', 'Modelo da Marinha');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (34, 'A Constituição portuguesa garante amplas liberdades cívicas, incluindo a liberdade de reunião, de expressão e o habeas corpus. Os serviços de segurança funcionam sob supervisão judicial e controlo parlamentar, e o país classifica-se consistentemente entre os mais pacíficos e livres nos índices internacionais.', 'internal_security', 'pt', 'Segurança Interna');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (35, 'Portugal opera uma economia mista onde o Estado desempenha um papel significativo através de empresas públicas, regulação e despesa social. Na sequência da crise financeira de 2008 e do programa de ajustamento do FMI, foram introduzidas reformas de mercado, mas o Estado mantém a titularidade de infraestruturas estratégicas e a Constituição consagra disposições para um modelo de economia mista.', 'economic_system', 'pt', 'Sistema Económico');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (36, 'Enquanto Estado-membro da UE, Portugal opera no âmbito do mercado único europeu e da pauta aduaneira comum, tornando o livre comércio com os parceiros da UE constitucionalmente garantido. Portugal está profundamente integrado no comércio global através das suas infraestruturas portuárias atlânticas, funcionando como porta de entrada entre a Europa, as Américas e África.', 'trade', 'pt', 'Política Comercial');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (37, 'Portugal aplica um imposto sobre o rendimento das pessoas singulares (IRS) com taxas progressivas entre 13,25% e 53%, bem como um imposto sobre as pessoas coletivas (IRC) com elementos progressivos. O sistema é globalmente redistributivo, embora a elevada dependência das receitas do IVA signifique que os impostos sobre o consumo também têm um peso considerável.', 'taxation', 'pt', 'Tributação');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (38, 'Após as radicais reformas agrárias que se seguiram à Revolução de 1974 no Alentejo, que coletivizaram as grandes herdades, a maior parte das terras agrícolas foi devolvida à propriedade privada nos anos 1980. Hoje, o setor agrícola português é predominantemente comercial, com grandes agronegócios no sul e pequenas explorações familiares no norte.', 'land_reform', 'pt', 'Reforma Agrária');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (39, 'Portugal concluiu a descolonização na sequência da Revolução dos Cravos de 1974, relinquindo os seus territórios africanos e reconhecendo a independência de Timor-Leste em 2002. Portugal não tem qualquer política colonial e é um firme apoiante dos quadros anti-colonialistas das Nações Unidas.', 'colonization', 'pt', 'Colonização');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (40, 'Portugal mantém duas forças policiais nacionais: a PSP para as zonas urbanas e a GNR para as zonas rurais e fronteiras. Ambas funcionam sob supervisão civil e respeitam os padrões legais democráticos, sem evidência de militarização sistemática ou de policiamento político.', 'policing', 'pt', 'Policiamento');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (41, 'O ensino público universal está garantido pela Constituição portuguesa, com escolaridade obrigatória dos 6 aos 18 anos. O Estado financia e gere a maioria das escolas, embora as instituições privadas e cooperativas recebam subsídios públicos e representem uma minoria significativa das matrículas.', 'education', 'pt', 'Sistema de Ensino');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (42, 'O Serviço Nacional de Saúde (SNS) português, criado em 1979, garante cuidados de saúde universais e gratuitos no ponto de utilização para todos os cidadãos. Apesar do subfinanciamento crónico e das longas listas de espera, o SNS permanece o principal prestador de cuidados de saúde, complementado por um setor privado em crescimento.', 'healthcare', 'pt', 'Sistema de Saúde');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (43, 'A liberdade de expressão e de imprensa estão garantidas pela Constituição de 1976. Portugal classifica-se consistentemente no topo mundial em matéria de liberdade de imprensa. Existem leis contra o discurso de ódio, mas a sua aplicação é restrita, e o discurso político beneficia de ampla proteção constitucional.', 'free_speech', 'pt', 'Liberdade de Expressão');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (44, 'O Código do Trabalho português garante proteções sólidas, incluindo salário mínimo nacional, férias pagas e proteções significativas contra despedimento. Estes direitos foram consagrados após a revolução e mantêm-se constitucionalmente garantidos, apesar das pressões sofridas durante os períodos de austeridade.', 'labor_rights', 'pt', 'Direitos Laborais');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (45, 'O direito de constituir e filiação em sindicatos é constitucionalmente garantido em Portugal. Os trabalhadores têm liberdade de se organizar, fazer greve e negociar coletivamente. As principais confederações sindicais, CGTP e UGT, representam trabalhadores dos setores público e privado.', 'labor_associations', 'pt', 'Associações Laborais');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (46, 'As mulheres portuguesas adquiriram plena igualdade política e jurídica com a Constituição de 1976. Legislação de igualdade salarial, direitos de licença parental e quotas de género para cargos eleitos estão em vigor. Portugal classifica-se entre as nações mais igualitárias da UE, embora persistam disparidades na prática, particularmente na liderança do setor privado.', 'womens_rights', 'pt', 'Direitos das Mulheres');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (47, 'Portugal opera um sistema de segurança social contributivo que abrange pensões de velhice, subsídios de desemprego e apoio por incapacidade. O sistema sofreu cortes significativos durante o programa de ajustamento do FMI de 2011-2014, mas foi parcialmente restaurado e alargado desde então.', 'welfare', 'pt', 'Bem-Estar Social');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (48, 'Portugal opera uma política de imigração controlada no âmbito do espaço Schengen da UE. Enquanto destino de migrantes de países lusófonos de África e do Brasil, Portugal estabeleceu vias legais específicas e programas de integração, embora o controlo da imigração se tenha intensificado nos últimos anos.', 'migration', 'pt', 'Migração');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (49, 'A escolaridade é obrigatória em Portugal dos 6 aos 18 anos e o trabalho infantil é proibido. Os serviços de proteção à infância são assegurados pelo Estado e por organizações não governamentais credenciadas. Portugal cumpre os padrões de proteção à infância da UE em todos os indicadores principais.', 'children_rights', 'pt', 'Direitos das Crianças');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (50, 'A escravatura foi abolida em Portugal em 1761 no território continental e em 1869 nas colónias. Todas as formas de trabalho forçado e tráfico de seres humanos estão tipificadas no Código Penal. Portugal é signatário de todas as principais convenções internacionais contra a escravatura e o tráfico de pessoas.', 'slavery', 'pt', 'Escravidão');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (51, 'Portugal comprometeu-se com a neutralidade carbónica até 2045 e expandiu significativamente as energias renováveis — mais de 60% da eletricidade foi gerada a partir de fontes renováveis nos últimos anos. Contudo, os compromissos de descarbonização total nos transportes e na indústria permanecem moderados face aos Estados-membros da UE mais ambiciosos.', 'environment', 'pt', 'Ambiente');
INSERT INTO public.policy_group_translations (id, classification_reason, group_id, locale, name) VALUES (52, 'O mercado habitacional português combina um mercado privado de arrendamento e propriedade com um parque de habitação pública limitado. Após a crise de acessibilidade habitacional provocada pela turistificação e gentrificação, o governo introduziu controlos de rendas e programas de habitação pública, embora os críticos considerem as intervenções do lado da oferta insuficientes.', 'housing', 'pt', 'Habitação');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('governance', 'power_structure', 'parliamentary_republic', 0, '🏛️');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('distribution_of_power', 'power_structure', 'universal_suffrage', 1, '⚖️');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('citizenship', 'power_structure', 'multicultural', 2, '🪪');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('church_state', 'power_structure', 'separation_of_church_and_state', 3, '⛪');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('bureaucracy', 'power_structure', 'appointed_bureaucrats', 4, '📋');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('army', 'power_structure', 'professional_army', 5, '🪖');
