INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('trade', 'economy', 'free_trade', 1, '🚢');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('taxation', 'economy', 'graduated', 2, '📊');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('land_reform', 'economy', 'commercialized_agriculture', 3, '🌾');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('colonization', 'economy', 'no_colonial_affairs', 4, '🗺️');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('policing', 'economy', 'dedicated_police_force', 5, '🚔');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('education', 'economy', 'public_schools', 6, '📚');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('healthcare', 'economy', 'public_health_insurance', 7, '🏥');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('free_speech', 'human_rights', 'protected_speech', 0, '🗣️');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('labor_rights', 'human_rights', 'workers_protections', 1, '⚒️');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('labor_associations', 'human_rights', 'right_to_associate', 2, '🤝');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('womens_rights', 'human_rights', 'womens_suffrage', 3, '♀️');
INSERT INTO public.policy_groups (id, category_id, current_option_id, display_order, icon) VALUES ('welfare', 'human_rights', 'old_age_pension', 4, '🛡️');
