INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (1, 'A hereditary head of state holds power, with authority varying from absolute to ceremonial depending on other laws.', 'en', 'Monarchy', 'monarchy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (2, 'A monarchy where the crown actively promotes social welfare and reforms to maintain popular legitimacy.', 'en', 'Social Monarchy', 'social_monarchy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (3, 'A directly elected president holds executive power. Head of state and head of government are the same.', 'en', 'Presidential Republic', 'presidential_republic');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (4, 'An elected parliament forms the government. A ceremonial president or similar figure serves as head of state.', 'en', 'Parliamentary Republic', 'parliamentary_republic');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (5, 'Religious authorities hold political power. Law is derived from religious doctrine.', 'en', 'Theocracy', 'theocracy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (6, 'The state is organised around economic corporations and guilds rather than individual representation.', 'en', 'Corporate State', 'corporate_state');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (7, 'Power is held by elected workers'' and soldiers'' councils. A socialist system of governance.', 'en', 'Council Republic', 'council_republic');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (8, 'All power concentrated in a single ruler or ruling body with no formal checks on authority.', 'en', 'Autocracy', 'autocracy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (9, 'Power held by a small privileged class, typically landowners, aristocrats, or wealthy elites.', 'en', 'Oligarchy', 'oligarchy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (10, 'Only landowners may vote. Political rights are tied to property ownership.', 'en', 'Landed Voting', 'landed_voting');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (11, 'Voting rights weighted by wealth. Wealthier citizens have more political influence.', 'en', 'Wealth Voting', 'wealth_voting');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (12, 'Voting rights restricted by income or property thresholds. A limited franchise.', 'en', 'Census Suffrage', 'census_suffrage');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (13, 'All adult citizens may vote equally regardless of wealth, gender, or background.', 'en', 'Universal Suffrage', 'universal_suffrage');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (14, 'Governance delegated to experts and technocrats insulated from popular pressure.', 'en', 'Technocracy', 'technocracy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (15, 'Only one political party is permitted. Elections, if held, are non-competitive.', 'en', 'Single-Party State', 'single_party_state');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (16, 'No formal state authority. Communities self-govern without central oversight.', 'en', 'Anarchy', 'anarchy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (17, 'All residents are subjects of the state with equal basic rights regardless of culture or origin.', 'en', 'Subjecthood', 'subjecthood');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (18, 'Citizenship and full rights restricted to a specific ethnic group. Others are excluded.', 'en', 'Ethnostate', 'ethnostate');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (19, 'The dominant culture holds privileged status. Minorities face legal disadvantages.', 'en', 'National Supremacy', 'national_supremacy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (20, 'Races are legally separated with different rights and access to public services.', 'en', 'Racial Segregation', 'racial_segregation');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (21, 'Certain cultural groups are excluded from political participation and full citizenship.', 'en', 'Cultural Exclusion', 'cultural_exclusion');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (22, 'All cultures enjoy equal rights and legal protections. Cultural diversity is formally recognised.', 'en', 'Multiculturalism', 'multicultural');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (23, 'An official religion is endorsed by the state. Other faiths face restrictions or are tolerated at the state''s discretion.', 'en', 'State Religion', 'state_religion');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (24, 'All religions are tolerated. The state does not endorse any faith but allows religious practice.', 'en', 'Freedom of Conscience', 'freedom_of_conscience');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (25, 'A formal wall between religious institutions and government. Neither influences the other.', 'en', 'Separation of Church and State', 'separation_of_church_and_state');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (26, 'The state actively promotes secularism and suppresses or discourages religious practice.', 'en', 'State Atheism', 'state_atheism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (27, 'Government positions passed down through noble or family lineages. Birth determines office.', 'en', 'Hereditary Bureaucrats', 'hereditary_bureaucrats');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (28, 'Officials selected by political leadership. Loyalty and patronage determine appointments.', 'en', 'Appointed Bureaucrats', 'appointed_bureaucrats');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (29, 'Administrators chosen by popular vote or representative bodies. Accountability to voters.', 'en', 'Elected Bureaucrats', 'elected_bureaucrats');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (30, 'No standing army. Irregular forces raised from the population in times of war. Cheap but weak.', 'en', 'Peasant Levies', 'peasant_levies');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (31, 'A permanent volunteer force of trained soldiers. High quality but expensive to maintain.', 'en', 'Professional Army', 'professional_army');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (32, 'A large reserve force of citizen-soldiers. Limited standing army but mass mobilisation capability.', 'en', 'National Militia', 'national_militia');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (33, 'Universal military service. A large standing army combined with extensive reserve capacity.', 'en', 'Mass Conscription', 'mass_conscription');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (34, 'The country maintains no meaningful naval capability.', 'en', 'No Naval Force', 'no_naval_force');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (35, 'A small fleet focused entirely on protecting home waters and coastlines.', 'en', 'Coastal Defense', 'coastal_defense');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (36, 'A navy sized and equipped to secure maritime trade routes and protect commercial interests.', 'en', 'Trade Protection', 'trade_protection');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (37, 'A blue-water navy capable of operating far from home and projecting force internationally.', 'en', 'Power Projection', 'power_projection');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (38, 'Civil liberties are actively protected. State security apparatus is constrained by law and oversight.', 'en', 'Guaranteed Liberties', 'guaranteed_liberties');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (39, 'A domestic security force focused on protecting the state from external and internal threats.', 'en', 'Homeland Defense Force', 'homeland_defense_force');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (40, 'A political police force that monitors and suppresses dissent. Civil liberties are curtailed.', 'en', 'Secret Police', 'secret_police');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (41, 'A pre-industrial subsistence economy. Limited market activity and strong local self-sufficiency.', 'en', 'Traditionalism', 'traditionalism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (42, 'The economy centres on agriculture. Industry is discouraged in favour of rural landowning classes.', 'en', 'Agrarianism', 'agrarianism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (43, 'A mixed economy where the state actively regulates markets, owns key industries, and steers investment.', 'en', 'Interventionism', 'interventionism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (44, 'Minimal state interference. Free markets determine wages, prices and production with little regulation.', 'en', 'Laissez-Faire', 'laissez_faire');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (45, 'Enterprises owned and managed collectively by workers. Market mechanisms retained but capital socialised.', 'en', 'Cooperative Ownership', 'cooperative_ownership');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (46, 'The state directs all production and distribution. Private ownership of enterprise is abolished.', 'en', 'Command Economy', 'command_economy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (47, 'The country withdraws from international trade. Economic self-sufficiency prioritised above all.', 'en', 'Isolationism', 'isolationism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (48, 'Trade managed to accumulate national wealth. Exports encouraged, imports restricted through tariffs.', 'en', 'Mercantilism', 'mercantilism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (49, 'High tariffs shield domestic industries from foreign competition. Strategic sectors prioritised.', 'en', 'Protectionism', 'protectionism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (50, 'Open borders for goods and capital. Comparative advantage drives specialisation and growth.', 'en', 'Free Trade', 'free_trade');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (51, 'Revenue raised primarily through taxes on goods and services. Burden falls on consumers.', 'en', 'Consumption-Based Taxation', 'consumption_based');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (52, 'Revenue raised primarily through taxes on land and agricultural output. Targets landowners.', 'en', 'Land-Based Taxation', 'land_based');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (53, 'A flat fee levied equally on all citizens regardless of income or wealth.', 'en', 'Per-Capita Taxation', 'per_capita');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (54, 'A single tax rate applied equally to all incomes. Simple and predictable.', 'en', 'Proportional Taxation', 'proportional');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (55, 'Progressive rates that rise with income. Higher earners contribute proportionally more.', 'en', 'Graduated Taxation', 'graduated');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (56, 'Peasants are legally bound to land owned by nobles. Labour obligations enforced by law.', 'en', 'Serfdom', 'serfdom');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (57, 'Peasants rent land from landowners. Subject to eviction and dependent on landlord goodwill.', 'en', 'Tenant Farmers', 'tenant_farmers');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (58, 'Large estates produce for market. Tenant farmers and wage labour replace traditional arrangements.', 'en', 'Commercialized Agriculture', 'commercialized_agriculture');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (59, 'Small independent farmers own their land. Subsistence and small-market farming predominates.', 'en', 'Peasant Proprietorship', 'peasant_proprietorship');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (60, 'Agricultural land managed collectively by the state or communes. Private farming abolished.', 'en', 'Collectivized Agriculture', 'collectivized_agriculture');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (61, 'The state has no colonial policy. No formal structures for settling or exploiting foreign territories.', 'en', 'No Colonial Affairs', 'no_colonial_affairs');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (62, 'Settlers encouraged to occupy and develop unclaimed or frontier lands with state support.', 'en', 'Frontier Colonization', 'frontier_colonization');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (63, 'Organised migration of citizens to colonies. State-sponsored population transfer to new territories.', 'en', 'Colonial Resettlement', 'colonial_resettlement');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (64, 'Colonies exist to extract resources for the benefit of the metropole. Native populations subordinated.', 'en', 'Colonial Exploitation', 'colonial_exploitation');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (65, 'No organised law enforcement. Order maintained locally or not at all.', 'en', 'No Police', 'no_police');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (66, 'Policing devolved to local communities. Officers embedded in and accountable to their area.', 'en', 'Local Police Force', 'local_police_force');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (67, 'A professional national police service. Uniform standards and centralised command.', 'en', 'Dedicated Police Force', 'dedicated_police_force');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (68, 'Police equipped and trained to military standards. Emphasis on control and order over rights.', 'en', 'Militarized Police', 'militarized_police');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (69, 'No state provision of education. Literacy and learning left entirely to families and private initiative.', 'en', 'No Schools', 'no_schools');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (70, 'Education provided primarily by religious institutions. Curriculum reflects religious values.', 'en', 'Religious Schools', 'religious_schools');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (71, 'Education provided by private institutions. Quality varies by ability to pay.', 'en', 'Private Schools', 'private_schools');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (72, 'State-funded universal education. Free at point of use and standardised across the country.', 'en', 'Public Schools', 'public_schools');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (73, 'No state involvement in healthcare. Medical care entirely a private matter.', 'en', 'No Health System', 'no_health_system');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (74, 'Healthcare provided by charitable and religious organisations for those who cannot afford private care.', 'en', 'Charity Hospitals', 'charity_hospitals');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (75, 'Medical care financed through private insurance. Access determined by ability to pay premiums.', 'en', 'Private Health Insurance', 'private_health_insurance');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (76, 'State-funded healthcare available to all citizens regardless of income.', 'en', 'Public Health Insurance', 'public_health_insurance');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (77, 'All political opposition is criminalised. Freedom of expression does not exist.', 'en', 'Outlawed Dissent', 'outlawed_dissent');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (78, 'The state controls media and public discourse. Criticism of government is restricted.', 'en', 'Censorship', 'censorship');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (79, 'Citizens may gather and organise freely. Public debate is permitted though not fully protected.', 'en', 'Right of Assembly', 'right_of_assembly');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (80, 'Freedom of expression is a fundamental right. The state actively protects political speech.', 'en', 'Protected Speech', 'protected_speech');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (81, 'Workers have no legal protections. Employers dictate all terms of employment.', 'en', 'No Workers'' Rights', 'no_workers_rights');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (82, 'Basic workplace regulations exist but enforcement is weak and rights are limited.', 'en', 'Regulatory Bodies', 'regulatory_bodies');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (83, 'Strong legal protections for workers including minimum wage, safety standards, and job security.', 'en', 'Workers'' Protections', 'workers_protections');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (84, 'Workers organised into trade guilds that regulate professions and negotiate with employers.', 'en', 'Guild System', 'guild_system');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (85, 'Unions are banned. Workers may not collectively organise or strike.', 'en', 'Combination Acts', 'combination_acts');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (86, 'Unions may exist but strikes are heavily restricted or illegal.', 'en', 'Anti-Strike Laws', 'anti_strike_laws');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (87, 'Workers may freely form unions and engage in collective bargaining.', 'en', 'Right to Associate', 'right_to_associate');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (88, 'Unions are integrated into the state structure. Collective bargaining is managed and controlled.', 'en', 'Corporatized Unions', 'corporatized_unions');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (89, 'Workers'' councils directly manage workplaces. A radical form of industrial democracy.', 'en', 'Factory Councils', 'factory_councils');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (90, 'Women are legal dependants of male relatives. They cannot own property or act independently.', 'en', 'Legal Guardianship', 'legal_guardianship');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (91, 'Women may own property but remain excluded from political participation.', 'en', 'Propertied Women', 'propertied_women');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (92, 'Women have the right to work but remain excluded from voting and political life.', 'en', 'Women in the Workplace', 'women_in_the_workplace');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (93, 'Women enjoy full legal and political equality including the right to vote and hold office.', 'en', 'Women''s Suffrage', 'womens_suffrage');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (94, 'No state support for the poor, unemployed, or elderly. Survival is entirely an individual matter.', 'en', 'No Social Security', 'no_social_security');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (95, 'Minimal state support for the destitute. Recipients face strict conditions and social stigma.', 'en', 'Poor Laws', 'poor_laws');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (96, 'The state supplements low wages to guarantee a minimum standard of living.', 'en', 'Wage Subsidies', 'wage_subsidies');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (97, 'State-funded income for the elderly. A broader social security system with multiple benefits.', 'en', 'Old Age Pension', 'old_age_pension');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (98, 'Free movement for all. No restrictions on who may enter, settle, or work.', 'en', 'No Migration Controls', 'no_migration_controls');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (99, 'Managed immigration with checks and quotas. Legal pathways exist but are regulated.', 'en', 'Migration Controls', 'migration_controls');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (100, 'Near-total restriction on immigration. Entry is only permitted in exceptional circumstances.', 'en', 'Closed Borders', 'closed_borders');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (101, 'Children may be employed. No restrictions on their use as labour.', 'en', 'Child Labor Allowed', 'child_labor_allowed');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (102, 'Child labour is limited. Some protections exist but are not comprehensively enforced.', 'en', 'Restricted Child Labor', 'restricted_child_labor');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (103, 'Education is mandatory for children. Child labour is banned and welfare services are robust.', 'en', 'Compulsory Primary School', 'compulsory_primary_school');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (104, 'All forms of slavery are illegal. Forced labour is criminalised throughout the territory.', 'en', 'Slavery Banned', 'slavery_banned');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (105, 'Slavery is banned domestically but permitted in colonial territories.', 'en', 'Colonial Slavery', 'colonial_slavery');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (106, 'People may be enslaved to pay off debts. A form of bondage with legal sanction.', 'en', 'Debt Slavery', 'debt_slavery');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (107, 'The buying and selling of enslaved people is legal and practiced.', 'en', 'Slave Trade', 'slave_trade');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (108, 'Slavery is being phased out but former enslaved people remain in bonded conditions.', 'en', 'Legacy Slavery', 'legacy_slavery');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (109, 'Aggressive decarbonisation targets, carbon tax, and heavy investment in renewables.', 'en', 'Green Transition', 'green_new_deal');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (110, 'Emissions targets with flexibility for industry. Incentives prioritised over mandates.', 'en', 'Moderate Regulation', 'moderate_green');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (111, 'Environmental rules rolled back. Growth and industry prioritised over climate.', 'en', 'Deregulated', 'deregulated');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (112, 'Large-scale public housing construction. Rent caps and strong tenant protections.', 'en', 'Social Housing', 'social_housing');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (113, 'Public housing for low incomes alongside a regulated private market.', 'en', 'Mixed Approach', 'mixed_housing');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (114, 'Deregulated property market. Supply and demand set prices with minimal state intervention.', 'en', 'Free Market', 'free_market_housing');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (115, 'Um chefe de Estado hereditário detém o poder, com autoridade que varia entre o absolutismo e o cerimonial consoante as restantes leis.', 'pt', 'Monarquia', 'monarchy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (116, 'Uma monarquia em que a coroa promove ativamente o bem-estar social e reformas para manter a legitimidade popular.', 'pt', 'Monarquia Social', 'social_monarchy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (117, 'Um presidente eleito diretamente detém o poder executivo. O chefe de Estado e o chefe de governo são a mesma pessoa.', 'pt', 'República Presidencialista', 'presidential_republic');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (118, 'Um parlamento eleito forma o governo. Um presidente cerimonial, ou figura semelhante, exerce as funções de chefe de Estado.', 'pt', 'República Parlamentar', 'parliamentary_republic');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (119, 'As autoridades religiosas detêm o poder político. A lei deriva da doutrina religiosa.', 'pt', 'Teocracia', 'theocracy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (120, 'O Estado organiza-se em torno de corporações económicas e grémios, em vez da representação individual.', 'pt', 'Estado Corporativo', 'corporate_state');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (121, 'O poder é detido por conselhos eleitos de trabalhadores e soldados. Um sistema de governação socialista.', 'pt', 'República de Conselhos', 'council_republic');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (122, 'Todo o poder concentrado num único governante ou órgão de governo, sem quaisquer limites formais à autoridade.', 'pt', 'Autocracia', 'autocracy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (123, 'O poder é detido por uma pequena classe privilegiada, normalmente proprietários de terras, aristocratas ou elites ricas.', 'pt', 'Oligarquia', 'oligarchy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (124, 'Apenas os proprietários de terras podem votar. Os direitos políticos estão ligados à posse de propriedade.', 'pt', 'Voto por Propriedade', 'landed_voting');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (125, 'Direitos de voto ponderados pela riqueza. Os cidadãos mais ricos têm maior influência política.', 'pt', 'Voto por Riqueza', 'wealth_voting');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (126, 'Direitos de voto restringidos por limiares de rendimento ou propriedade. Um sufrágio limitado.', 'pt', 'Sufrágio Censitário', 'census_suffrage');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (127, 'Todos os cidadãos adultos podem votar em igualdade, independentemente da riqueza, género ou origem.', 'pt', 'Sufrágio Universal', 'universal_suffrage');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (128, 'A governação é delegada a peritos e tecnocratas, isolados da pressão popular.', 'pt', 'Tecnocracia', 'technocracy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (129, 'Apenas um partido político é permitido. As eleições, quando existem, não são competitivas.', 'pt', 'Estado de Partido Único', 'single_party_state');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (130, 'Não existe autoridade estatal formal. As comunidades autogovernam-se sem supervisão central.', 'pt', 'Anarquia', 'anarchy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (131, 'Todos os residentes são súbditos do Estado, com direitos básicos iguais independentemente da cultura ou origem.', 'pt', 'Súbditos', 'subjecthood');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (132, 'A cidadania e os direitos plenos restringidos a um grupo étnico específico. Os restantes são excluídos.', 'pt', 'Etno-Estado', 'ethnostate');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (133, 'A cultura dominante detém um estatuto privilegiado. As minorias enfrentam desvantagens legais.', 'pt', 'Supremacia Nacional', 'national_supremacy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (134, 'As raças são legalmente separadas, com direitos e acesso a serviços públicos distintos.', 'pt', 'Segregação Racial', 'racial_segregation');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (135, 'Determinados grupos culturais são excluídos da participação política e da cidadania plena.', 'pt', 'Exclusão Cultural', 'cultural_exclusion');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (136, 'Todas as culturas gozam de direitos iguais e proteção legal. A diversidade cultural é formalmente reconhecida.', 'pt', 'Multiculturalismo', 'multicultural');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (137, 'Uma religião oficial é consagrada pelo Estado. As restantes confissões enfrentam restrições ou são toleradas ao critério do Estado.', 'pt', 'Religião de Estado', 'state_religion');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (138, 'Todas as religiões são toleradas. O Estado não consagra nenhuma fé, mas permite a prática religiosa.', 'pt', 'Liberdade de Consciência', 'freedom_of_conscience');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (139, 'Uma barreira formal entre as instituições religiosas e o governo. Nenhum influencia o outro.', 'pt', 'Separação entre Igreja e Estado', 'separation_of_church_and_state');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (140, 'O Estado promove ativamente o secularismo e reprime ou desencoraja a prática religiosa.', 'pt', 'Ateísmo de Estado', 'state_atheism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (141, 'Os cargos governamentais são transmitidos através de linhagens nobres ou familiares. O nascimento determina o cargo.', 'pt', 'Burocratas Hereditários', 'hereditary_bureaucrats');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (142, 'Os funcionários são escolhidos pela liderança política. A lealdade e o clientelismo determinam as nomeações.', 'pt', 'Burocratas Nomeados', 'appointed_bureaucrats');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (143, 'Os administradores são escolhidos por voto popular ou por órgãos representativos. Prestação de contas perante os eleitores.', 'pt', 'Burocratas Eleitos', 'elected_bureaucrats');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (144, 'Não existe exército permanente. Forças irregulares são recrutadas da população em tempo de guerra. Barato, mas fraco.', 'pt', 'Recrutamento Camponês', 'peasant_levies');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (145, 'Uma força permanente de soldados voluntários e treinados. Alta qualidade, mas dispendiosa de manter.', 'pt', 'Exército Profissional', 'professional_army');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (146, 'Uma grande força de reserva de cidadãos-soldados. Exército permanente limitado, mas com capacidade de mobilização em massa.', 'pt', 'Milícia Nacional', 'national_militia');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (147, 'Serviço militar universal. Um grande exército permanente combinado com ampla capacidade de reserva.', 'pt', 'Conscrição em Massa', 'mass_conscription');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (148, 'O país não mantém qualquer capacidade naval significativa.', 'pt', 'Sem Força Naval', 'no_naval_force');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (149, 'Uma pequena frota focada inteiramente na proteção das águas e linhas costeiras nacionais.', 'pt', 'Defesa Costeira', 'coastal_defense');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (150, 'Uma marinha dimensionada e equipada para proteger as rotas comerciais marítimas e os interesses comerciais.', 'pt', 'Proteção do Comércio', 'trade_protection');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (151, 'Uma marinha de águas azuis capaz de operar longe de casa e projetar poder internacionalmente.', 'pt', 'Projeção de Poder', 'power_projection');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (152, 'As liberdades cívicas são ativamente protegidas. O aparelho de segurança do Estado é limitado pela lei e pela supervisão.', 'pt', 'Liberdades Garantidas', 'guaranteed_liberties');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (153, 'Uma força de segurança interna focada na proteção do Estado contra ameaças externas e internas.', 'pt', 'Força de Defesa Interna', 'homeland_defense_force');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (154, 'Uma polícia política que vigia e reprime a dissidência. As liberdades cívicas são cerceadas.', 'pt', 'Polícia Secreta', 'secret_police');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (155, 'Uma economia de subsistência pré-industrial. Atividade de mercado limitada e forte autossuficiência local.', 'pt', 'Tradicionalismo', 'traditionalism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (156, 'A economia centra-se na agricultura. A indústria é desencorajada em favor das classes proprietárias rurais.', 'pt', 'Agrarismo', 'agrarianism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (157, 'Uma economia mista em que o Estado regula ativamente os mercados, detém indústrias-chave e orienta o investimento.', 'pt', 'Intervencionismo', 'interventionism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (158, 'Interferência estatal mínima. Os mercados livres determinam salários, preços e produção com pouca regulação.', 'pt', 'Laissez-Faire', 'laissez_faire');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (159, 'Empresas detidas e geridas coletivamente pelos trabalhadores. Mecanismos de mercado mantidos, mas o capital é socializado.', 'pt', 'Propriedade Cooperativa', 'cooperative_ownership');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (160, 'O Estado dirige toda a produção e distribuição. A propriedade privada das empresas é abolida.', 'pt', 'Economia Planificada', 'command_economy');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (161, 'O país retira-se do comércio internacional. A autossuficiência económica é prioritária acima de tudo.', 'pt', 'Isolacionismo', 'isolationism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (162, 'Comércio gerido para acumular riqueza nacional. Exportações incentivadas, importações restringidas por tarifas.', 'pt', 'Mercantilismo', 'mercantilism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (163, 'Tarifas elevadas protegem as indústrias nacionais da concorrência estrangeira. Setores estratégicos priorizados.', 'pt', 'Protecionismo', 'protectionism');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (164, 'Fronteiras abertas a bens e capital. A vantagem comparativa impulsiona a especialização e o crescimento.', 'pt', 'Livre Comércio', 'free_trade');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (165, 'A receita é obtida sobretudo através de impostos sobre bens e serviços. O encargo recai sobre os consumidores.', 'pt', 'Tributação sobre o Consumo', 'consumption_based');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (166, 'A receita é obtida sobretudo através de impostos sobre a terra e a produção agrícola. Visa os proprietários fundiários.', 'pt', 'Tributação sobre a Terra', 'land_based');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (167, 'Uma taxa fixa cobrada igualmente a todos os cidadãos, independentemente do rendimento ou riqueza.', 'pt', 'Tributação por Capita', 'per_capita');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (168, 'Uma taxa de imposto única aplicada igualmente a todos os rendimentos. Simples e previsível.', 'pt', 'Tributação Proporcional', 'proportional');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (169, 'Taxas progressivas que aumentam com o rendimento. Os que mais ganham contribuem proporcionalmente mais.', 'pt', 'Tributação Progressiva', 'graduated');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (170, 'Os camponeses estão legalmente vinculados a terras de propriedade da nobreza. Obrigações laborais impostas por lei.', 'pt', 'Servidão', 'serfdom');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (171, 'Os camponeses arrendam terras aos proprietários. Sujeitos a despejo e dependentes da boa vontade do senhorio.', 'pt', 'Rendeiros', 'tenant_farmers');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (172, 'Grandes explorações produzem para o mercado. Rendeiros e trabalho assalariado substituem os arranjos tradicionais.', 'pt', 'Agricultura Comercial', 'commercialized_agriculture');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (173, 'Pequenos agricultores independentes possuem as suas terras. Predomina a agricultura de subsistência e de pequeno mercado.', 'pt', 'Pequena Propriedade Camponesa', 'peasant_proprietorship');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (174, 'Terras agrícolas geridas coletivamente pelo Estado ou por comunas. A agricultura privada é abolida.', 'pt', 'Agricultura Coletivizada', 'collectivized_agriculture');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (175, 'O Estado não tem política colonial. Não existem estruturas formais para colonizar ou explorar territórios estrangeiros.', 'pt', 'Sem Assuntos Coloniais', 'no_colonial_affairs');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (176, 'Os colonos são incentivados a ocupar e desenvolver terras de fronteira ou não reclamadas, com apoio do Estado.', 'pt', 'Colonização de Fronteira', 'frontier_colonization');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (177, 'Migração organizada de cidadãos para as colónias. Transferência de população patrocinada pelo Estado para novos territórios.', 'pt', 'Reassentamento Colonial', 'colonial_resettlement');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (178, 'As colónias existem para extrair recursos em benefício da metrópole. As populações nativas são subordinadas.', 'pt', 'Exploração Colonial', 'colonial_exploitation');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (179, 'Não existe aplicação organizada da lei. A ordem é mantida localmente ou não é mantida de todo.', 'pt', 'Sem Polícia', 'no_police');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (180, 'O policiamento é delegado às comunidades locais. Os agentes estão integrados na sua área e perante ela respondem.', 'pt', 'Força Policial Local', 'local_police_force');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (181, 'Um serviço de polícia nacional profissional. Padrões uniformes e comando centralizado.', 'pt', 'Força Policial Dedicada', 'dedicated_police_force');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (182, 'Polícia equipada e treinada segundo padrões militares. Ênfase no controlo e na ordem em detrimento dos direitos.', 'pt', 'Polícia Militarizada', 'militarized_police');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (183, 'Não há provisão estatal de ensino. A literacia e a aprendizagem ficam a cargo das famílias e da iniciativa privada.', 'pt', 'Sem Escolas', 'no_schools');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (184, 'O ensino é fornecido sobretudo por instituições religiosas. O currículo reflete valores religiosos.', 'pt', 'Escolas Religiosas', 'religious_schools');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (185, 'O ensino é fornecido por instituições privadas. A qualidade varia consoante a capacidade de pagamento.', 'pt', 'Escolas Privadas', 'private_schools');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (186, 'Ensino universal financiado pelo Estado. Gratuito no ponto de utilização e padronizado em todo o país.', 'pt', 'Escolas Públicas', 'public_schools');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (187, 'Não há envolvimento do Estado nos cuidados de saúde. Os cuidados médicos são uma questão inteiramente privada.', 'pt', 'Sem Sistema de Saúde', 'no_health_system');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (188, 'Cuidados de saúde fornecidos por organizações caritativas e religiosas a quem não pode pagar cuidados privados.', 'pt', 'Hospitais de Caridade', 'charity_hospitals');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (189, 'Cuidados médicos financiados por seguros privados. O acesso é determinado pela capacidade de pagar prémios.', 'pt', 'Seguro de Saúde Privado', 'private_health_insurance');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (190, 'Cuidados de saúde financiados pelo Estado, disponíveis a todos os cidadãos independentemente do rendimento.', 'pt', 'Seguro de Saúde Público', 'public_health_insurance');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (191, 'Toda a oposição política é criminalizada. A liberdade de expressão não existe.', 'pt', 'Dissidência Proibida', 'outlawed_dissent');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (192, 'O Estado controla os meios de comunicação e o discurso público. A crítica ao governo é restringida.', 'pt', 'Censura', 'censorship');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (193, 'Os cidadãos podem reunir-se e organizar-se livremente. O debate público é permitido, embora não plenamente protegido.', 'pt', 'Direito de Reunião', 'right_of_assembly');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (194, 'A liberdade de expressão é um direito fundamental. O Estado protege ativamente o discurso político.', 'pt', 'Expressão Protegida', 'protected_speech');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (195, 'Os trabalhadores não têm proteções legais. Os empregadores ditam todas as condições de trabalho.', 'pt', 'Sem Direitos dos Trabalhadores', 'no_workers_rights');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (196, 'Existem regulamentos laborais básicos, mas a fiscalização é fraca e os direitos são limitados.', 'pt', 'Órgãos Reguladores', 'regulatory_bodies');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (197, 'Proteções legais sólidas para os trabalhadores, incluindo salário mínimo, normas de segurança e estabilidade no emprego.', 'pt', 'Proteções dos Trabalhadores', 'workers_protections');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (198, 'Trabalhadores organizados em grémios profissionais que regulam as profissões e negoceiam com os empregadores.', 'pt', 'Sistema de Grémios', 'guild_system');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (199, 'Os sindicatos são proibidos. Os trabalhadores não podem organizar-se coletivamente nem fazer greve.', 'pt', 'Proibição de Coligações', 'combination_acts');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (200, 'Os sindicatos podem existir, mas as greves são fortemente restringidas ou ilegais.', 'pt', 'Leis Antigreve', 'anti_strike_laws');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (201, 'Os trabalhadores podem formar livremente sindicatos e participar em negociação coletiva.', 'pt', 'Direito de Associação', 'right_to_associate');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (202, 'Os sindicatos estão integrados na estrutura do Estado. A negociação coletiva é gerida e controlada.', 'pt', 'Sindicatos Corporativos', 'corporatized_unions');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (203, 'Conselhos de trabalhadores gerem diretamente os locais de trabalho. Uma forma radical de democracia industrial.', 'pt', 'Conselhos de Fábrica', 'factory_councils');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (204, 'As mulheres são dependentes legais de familiares do sexo masculino. Não podem possuir propriedade nem agir de forma independente.', 'pt', 'Tutela Legal', 'legal_guardianship');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (205, 'As mulheres podem possuir propriedade, mas permanecem excluídas da participação política.', 'pt', 'Mulheres Proprietárias', 'propertied_women');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (206, 'As mulheres têm direito a trabalhar, mas permanecem excluídas do voto e da vida política.', 'pt', 'Mulheres no Trabalho', 'women_in_the_workplace');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (207, 'As mulheres gozam de plena igualdade legal e política, incluindo o direito de votar e de ocupar cargos.', 'pt', 'Sufrágio Feminino', 'womens_suffrage');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (208, 'Não há apoio estatal aos pobres, desempregados ou idosos. A sobrevivência é uma questão inteiramente individual.', 'pt', 'Sem Segurança Social', 'no_social_security');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (209, 'Apoio estatal mínimo aos indigentes. Os beneficiários enfrentam condições estritas e estigma social.', 'pt', 'Leis dos Pobres', 'poor_laws');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (210, 'O Estado complementa os salários baixos para garantir um nível de vida mínimo.', 'pt', 'Subsídios Salariais', 'wage_subsidies');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (211, 'Rendimento financiado pelo Estado para os idosos. Um sistema de segurança social mais amplo, com múltiplas prestações.', 'pt', 'Pensão de Velhice', 'old_age_pension');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (212, 'Livre circulação para todos. Sem restrições sobre quem pode entrar, fixar-se ou trabalhar.', 'pt', 'Sem Controlos Migratórios', 'no_migration_controls');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (213, 'Imigração gerida com verificações e quotas. Existem vias legais, mas são reguladas.', 'pt', 'Controlos Migratórios', 'migration_controls');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (214, 'Restrição quase total à imigração. A entrada só é permitida em circunstâncias excecionais.', 'pt', 'Fronteiras Fechadas', 'closed_borders');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (215, 'As crianças podem ser empregadas. Não há restrições à sua utilização como mão de obra.', 'pt', 'Trabalho Infantil Permitido', 'child_labor_allowed');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (216, 'O trabalho infantil é limitado. Existem algumas proteções, mas não são plenamente fiscalizadas.', 'pt', 'Trabalho Infantil Restrito', 'restricted_child_labor');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (217, 'A escolaridade é obrigatória para as crianças. O trabalho infantil é proibido e os serviços de proteção são sólidos.', 'pt', 'Ensino Primário Obrigatório', 'compulsory_primary_school');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (218, 'Todas as formas de escravatura são ilegais. O trabalho forçado é criminalizado em todo o território.', 'pt', 'Escravatura Proibida', 'slavery_banned');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (219, 'A escravatura é proibida internamente, mas permitida nos territórios coloniais.', 'pt', 'Escravatura Colonial', 'colonial_slavery');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (220, 'As pessoas podem ser escravizadas para saldar dívidas. Uma forma de servidão com sanção legal.', 'pt', 'Escravatura por Dívida', 'debt_slavery');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (221, 'A compra e venda de pessoas escravizadas é legal e praticada.', 'pt', 'Comércio de Escravos', 'slave_trade');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (222, 'A escravatura está a ser eliminada, mas as antigas pessoas escravizadas permanecem em condições de servidão.', 'pt', 'Escravatura Residual', 'legacy_slavery');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (223, 'Metas agressivas de descarbonização, imposto sobre o carbono e forte investimento em energias renováveis.', 'pt', 'Transição Verde', 'green_new_deal');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (224, 'Metas de emissões com flexibilidade para a indústria. Incentivos privilegiados em vez de imposições.', 'pt', 'Regulação Moderada', 'moderate_green');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (225, 'Regras ambientais revogadas. O crescimento e a indústria são priorizados em detrimento do clima.', 'pt', 'Desregulado', 'deregulated');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (226, 'Construção em larga escala de habitação pública. Controlos de renda e fortes proteções dos inquilinos.', 'pt', 'Habitação Social', 'social_housing');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (227, 'Habitação pública para baixos rendimentos a par de um mercado privado regulado.', 'pt', 'Abordagem Mista', 'mixed_housing');
INSERT INTO public.policy_option_translations (id, description, locale, name, option_id) VALUES (228, 'Mercado imobiliário desregulado. A oferta e a procura definem os preços, com intervenção estatal mínima.', 'pt', 'Mercado Livre', 'free_market_housing');
