INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (1, 1, 'en', 'Housing', 'Backs public investment in affordable housing and rent regulation.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (2, 1, 'pt', 'Habitação', 'Defende investimento público em habitação acessível e regulação do arrendamento.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (3, 2, 'en', 'Economy', 'Favours a mixed economy with strong public services and balanced budgets.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (4, 2, 'pt', 'Economia', 'Aposta numa economia mista com serviços públicos fortes e contas equilibradas.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (5, 3, 'en', 'Europe', 'Strongly pro-European and committed to EU integration.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (6, 3, 'pt', 'Europa', 'Forte compromisso europeísta e integração na União Europeia.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (7, 4, 'en', 'Economy', 'Promotes tax cuts and support for small and medium enterprises.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (8, 4, 'pt', 'Economia', 'Promove a redução de impostos e o apoio às pequenas e médias empresas.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (9, 5, 'en', 'Health', 'Supports public-private partnerships in healthcare.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (10, 5, 'pt', 'Saúde', 'Defende parcerias entre o setor público e privado na saúde.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (11, 6, 'en', 'Decentralisation', 'Backs devolving powers to local government.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (12, 6, 'pt', 'Descentralização', 'Aposta na descentralização de competências para as autarquias.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (13, 7, 'en', 'Security', 'Calls for stronger police forces and tougher sentencing.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (14, 7, 'pt', 'Segurança', 'Defende reforço das forças de segurança e penas mais severas.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (15, 8, 'en', 'Immigration', 'Proposes tight control of immigration and borders.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (16, 8, 'pt', 'Imigração', 'Propõe controlo apertado da imigração e das fronteiras.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (17, 9, 'en', 'Corruption', 'Places the fight against corruption at the centre of its programme.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (18, 9, 'pt', 'Corrupção', 'Coloca o combate à corrupção no centro do seu programa.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (19, 10, 'en', 'Taxes', 'Advocates a significant reduction and simplification of taxes.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (20, 10, 'pt', 'Impostos', 'Defende uma redução significativa e simplificação dos impostos.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (21, 11, 'en', 'State', 'Proposes a smaller state and less economic regulation.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (22, 11, 'pt', 'Estado', 'Propõe um Estado mais pequeno e menos regulação da economia.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (23, 12, 'en', 'Freedom', 'Emphasises individual liberties and free enterprise.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (24, 12, 'pt', 'Liberdade', 'Enfatiza as liberdades individuais e a livre iniciativa.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (25, 13, 'en', 'Labour', 'Backs higher wages and stronger labour rights.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (26, 13, 'pt', 'Trabalho', 'Defende o aumento dos salários e o reforço dos direitos laborais.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (27, 14, 'en', 'Housing', 'Proposes rent controls and heavy public housing investment.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (28, 14, 'pt', 'Habitação', 'Propõe controlo de rendas e forte investimento público na habitação.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (29, 15, 'en', 'Climate', 'Pushes for a just and ambitious ecological transition.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (30, 15, 'pt', 'Clima', 'Aposta numa transição ecológica justa e ambiciosa.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (31, 16, 'en', 'Workers', 'Defends workers'' rights and collective bargaining.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (32, 16, 'pt', 'Trabalhadores', 'Defende os direitos dos trabalhadores e a contratação coletiva.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (33, 17, 'en', 'Public Services', 'Backs a strong public sector in health, education and transport.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (34, 17, 'pt', 'Serviços Públicos', 'Aposta num setor público forte na saúde, educação e transportes.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (35, 18, 'en', 'Sovereignty', 'Values national sovereignty vis-à-vis the European Union.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (36, 18, 'pt', 'Soberania', 'Valoriza a soberania nacional face à União Europeia.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (37, 19, 'en', 'Environment', 'Places environmental protection at the centre of policy.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (38, 19, 'pt', 'Ambiente', 'Coloca a proteção ambiental no centro da ação política.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (39, 20, 'en', 'Animal Welfare', 'Advocates stronger animal protection laws.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (40, 20, 'pt', 'Bem-estar Animal', 'Defende leis mais fortes para a proteção dos animais.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (41, 21, 'en', 'Sustainability', 'Promotes a sustainable, low-carbon economic model.');
INSERT INTO public.party_position_translations (id, position_id, locale, topic, summary) VALUES (42, 21, 'pt', 'Sustentabilidade', 'Promove um modelo económico sustentável e de baixo carbono.');
